-- CA Board of Registered Nursing
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_079', 'ETHICARA', 'STATE_STATUTE', 'CA', 'Cal. Bus. & Prof. Code §§ 2700-2838 (Nursing Practice Act)', 'BPC §§ 2700-2838', 'California Board of Registered Nursing — Nursing Practice Act', 'Governs licensure, practice, and discipline of registered nurses (RNs) and advanced practice registered nurses (APRNs) in California. The Board of Registered Nursing (BRN) sets education requirements, administers NCLEX-RN, issues licenses, and enforces disciplinary standards. Scope of practice includes assessment, planning, intervention, and evaluation of patient care. Nurse practitioners authorized for expanded scope under standardized procedures.', '["RN license required to practice nursing in California (§ 2725)","Education: graduation from BRN-approved nursing program","Examination: NCLEX-RN required for initial licensure","License renewal: every 2 years, 30 CE hours required (§ 2811.5)","Nurse Practitioner: national certification + BRN furnishing number for prescribing","Scope of practice: assessment, planning, intervention, evaluation (§ 2725)","Standardized procedures required for NP expanded scope (§ 2836.1)","Grounds for discipline: unprofessional conduct, substance abuse, incompetence (§ 2761)","Mandatory reporting: employer must report within 30 days of termination for cause (§ 2732.5)","Diversion Program available for substance abuse (§ 2770)"]', '[{"section":"2700-2705","description":"Board of Registered Nursing — creation and composition"},{"section":"2725","description":"Scope of practice — RN functions defined"},{"section":"2732.5","description":"Mandatory reporting of termination for cause"},{"section":"2736","description":"License required to practice nursing"},{"section":"2761","description":"Grounds for disciplinary action"},{"section":"2811.5","description":"Continuing education — 30 hours per renewal cycle"},{"section":"2836-2836.3","description":"Nurse Practitioner scope — standardized procedures, furnishing"},{"section":"2770-2770.10","description":"Diversion Program for substance-impaired nurses"}]', '["RN_license","NP_certification","CE_records","disciplinary_complaint","mandatory_report","standardized_procedure","scope_of_practice_analysis","diversion_agreement"]', '["professional-ethics-standards-audit"]', 'Board of Registered Nursing (BRN)', 0, 1, datetime('now'), datetime('now'));

-- CA Board of Pharmacy
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_080', 'ETHICARA', 'STATE_STATUTE', 'CA', 'Cal. Bus. & Prof. Code §§ 4000-4427 (Pharmacy Law)', 'BPC §§ 4000-4427', 'California Board of Pharmacy — Pharmacy Practice Act', 'Governs licensure, practice, and regulation of pharmacists, pharmacy technicians, intern pharmacists, and pharmacy premises in California. Board of Pharmacy oversees drug dispensing, compounding, controlled substance management, patient consultation requirements, and pharmacy ownership. Pharmacists must consult on new prescriptions, maintain patient profiles, and comply with CURES reporting.', '["Pharmacist license required to practice pharmacy (§ 4051)","Education: PharmD from ACPE-accredited program","Examination: NAPLEX + CPJE required for California licensure","License renewal: every 2 years, 30 CE hours required (§ 4231)","Pharmacy technician: registration with Board, ratio limits (§ 4115)","Patient consultation required for new prescriptions (§ 4052)","CURES reporting: dispensers must report Schedule II-IV within one working day (§ 4104)","Compounding: must comply with USP standards (§ 4126.8)","Controlled substances: DEA registration + state requirements (§ 4060)","Pharmacy ownership: disclosure of beneficial interest required (§ 4035)","Self-assessment: pharmacy must complete biennial self-assessment (§ 4427.7)"]', '[{"section":"4000-4008","description":"Board of Pharmacy — creation, composition, powers"},{"section":"4035-4043","description":"Pharmacy ownership and premises licensing"},{"section":"4051-4052","description":"Practice of pharmacy — functions, patient consultation"},{"section":"4060","description":"Controlled substances — furnishing requirements"},{"section":"4104","description":"CURES reporting — Schedule II-IV dispensing"},{"section":"4115","description":"Pharmacy technicians — duties, supervision ratios"},{"section":"4126.8","description":"Compounding — USP compliance requirements"},{"section":"4231","description":"Continuing education — 30 hours per cycle"},{"section":"4301","description":"Grounds for discipline — unprofessional conduct"},{"section":"4427-4427.8","description":"Self-assessment requirements"}]', '["pharmacist_license","pharmacy_permit","technician_registration","CE_records","CURES_report","self_assessment","compounding_log","disciplinary_complaint","controlled_substance_inventory","patient_consultation_record"]', '["professional-ethics-standards-audit"]', 'California Board of Pharmacy', 0, 1, datetime('now'), datetime('now'));

-- Dental Board of California
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_081', 'ETHICARA', 'STATE_STATUTE', 'CA', 'Cal. Bus. & Prof. Code §§ 1600-1976 (Dental Practice Act)', 'BPC §§ 1600-1976', 'Dental Board of California — Dental Practice Act', 'Governs licensure, practice, and discipline of dentists, dental hygienists, registered dental assistants, and dental auxiliaries in California. Dental Board sets education, examination, and continuing education standards. Scope of practice includes diagnosis, treatment planning, surgery, prescribing, and sedation/anesthesia permits. Infection control and radiation safety standards mandated.', '["License required to practice dentistry in California (§ 1625.1)","Education: graduation from CODA-accredited dental program","Examination: clinical exam + written law and ethics exam","License renewal: every 2 years, 50 CE hours required (§ 1715)","Dental hygienist: separate license, defined scope (§§ 1900-1966)","RDA: registered dental assistant with Board-approved education (§§ 1750-1753)","Sedation/anesthesia: separate permits required (§ 1646)","Infection control: compliance with OSHA and OSAP standards (§ 1680)","Mandatory reporting: professional misconduct, patient abuse (§ 1680.5)","Prescribing: DEA registration required for controlled substances","Mobile dental units and dental corporations regulated (§§ 1650.2, 1800)"]', '[{"section":"1600-1601","description":"Dental Board — creation, powers, composition"},{"section":"1625.1","description":"License required to practice dentistry"},{"section":"1628-1636","description":"Licensure requirements — education, examination"},{"section":"1646","description":"General anesthesia and sedation permits"},{"section":"1680","description":"Unprofessional conduct — grounds for discipline"},{"section":"1680.5","description":"Mandatory reporting requirements"},{"section":"1715","description":"Continuing education — 50 hours per renewal cycle"},{"section":"1750-1753","description":"Registered Dental Assistants — duties and scope"},{"section":"1900-1966","description":"Dental hygienists — licensure and scope of practice"}]', '["dental_license","hygienist_license","RDA_registration","CE_records","sedation_permit","infection_control_protocol","disciplinary_complaint","mandatory_report","radiation_safety_records"]', '["professional-ethics-standards-audit"]', 'Dental Board of California', 0, 1, datetime('now'), datetime('now'));

-- CA Board for Professional Engineers
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_082', 'ETHICARA', 'STATE_STATUTE', 'CA', 'Cal. Bus. & Prof. Code §§ 6700-6799 (Professional Engineers Act)', 'BPC §§ 6700-6799', 'California Board for Professional Engineers, Land Surveyors, and Geologists — Professional Engineers Act', 'Governs licensure and regulation of professional engineers (PE) in California across all branches: civil, electrical, mechanical, chemical, and others. PE license required to offer engineering services to the public. FE exam (Fundamentals of Engineering) followed by PE exam after qualifying experience. Engineers must stamp and sign all work. Practice without license is a misdemeanor.', '["PE license required to practice or offer engineering services to public (§ 6730)","Education: ABET-accredited engineering degree or equivalent","FE exam: Fundamentals of Engineering — first step to licensure","PE exam: Principles and Practice of Engineering — branch-specific","Experience: minimum qualifying experience under licensed PE supervision","License renewal: every 2 years (no mandatory CE for most branches)","Stamp and signature: PE must sign and stamp all engineering documents (§ 6735)","Practice without license: misdemeanor (§ 6787)","Exemptions: work under licensed PE supervision, industrial exemption (§ 6747)","Branches: civil, electrical, mechanical, chemical, fire protection, others","Civil engineer: additional authority for land surveying-related work (§ 6731.1)"]', '[{"section":"6700-6710","description":"Board — creation, composition, powers"},{"section":"6730","description":"License required — practice of professional engineering defined"},{"section":"6731-6731.1","description":"Civil engineering defined — additional authorities"},{"section":"6735","description":"Stamp and signature requirement for documents"},{"section":"6747","description":"Industrial exemption — employer employee relationship"},{"section":"6750-6758","description":"License requirements — education, examination, experience"},{"section":"6775","description":"Grounds for disciplinary action"},{"section":"6787","description":"Misdemeanor — practicing without license"}]', '["PE_license","FE_exam_records","PE_exam_records","engineering_stamp","disciplinary_complaint","industrial_exemption_analysis","experience_verification","scope_of_practice_analysis"]', '["professional-ethics-standards-audit"]', 'Board for Professional Engineers, Land Surveyors, and Geologists (BPELSG)', 0, 1, datetime('now'), datetime('now'));

-- CA Board of Accountancy — CPA Licensing
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_083', 'ETHICARA', 'STATE_STATUTE', 'CA', 'Cal. Bus. & Prof. Code §§ 5000-5158 (Accountancy Act)', 'BPC §§ 5000-5158', 'California Board of Accountancy — CPA Licensing and Regulation', 'Governs licensure and regulation of Certified Public Accountants in California. CBA oversees education requirements (150 semester units), Uniform CPA Examination, ethics examination, and experience requirements. CPAs perform attest services (audits, reviews, compilations), tax services, and advisory services. Peer review required for firms performing attest services. Continuing education: 80 hours per biennial renewal.', '["CPA license required for attest services (audits, reviews, compilations) (§ 5051)","Education: 150 semester units including accounting and business courses (§ 5093)","Examination: Uniform CPA Examination — four sections","Ethics examination: AICPA Professional Ethics exam required (§ 5092)","Experience: 12 months general accounting experience under licensed CPA (§ 5093)","License renewal: every 2 years, 80 CE hours required (§ 5026)","Peer review: required for firms performing attest services (§ 5076)","Practice privileges: out-of-state CPAs may practice under mobility provisions (§ 5096)","CPA firm: must register with CBA, designated partner must be CPA (§ 5079)","Grounds for discipline: fraud, negligence, conviction of crime (§ 5100)","Attest services: only licensed CPAs may issue audit opinions (§ 5051)"]', '[{"section":"5000-5015","description":"Board of Accountancy — creation, composition, powers"},{"section":"5051","description":"Attest services restricted to licensees"},{"section":"5070-5079","description":"CPA firm registration and requirements"},{"section":"5076","description":"Peer review requirement for attest firms"},{"section":"5092-5093","description":"Licensure requirements — education, exam, experience"},{"section":"5096","description":"Practice privileges — out-of-state mobility"},{"section":"5100","description":"Grounds for disciplinary action"},{"section":"5026","description":"Continuing education — 80 hours per biennial cycle"}]', '["CPA_license","firm_registration","peer_review_report","CE_records","disciplinary_complaint","attest_engagement","ethics_exam_records","experience_verification"]', '["professional-ethics-standards-audit"]', 'California Board of Accountancy (CBA)', 0, 1, datetime('now'), datetime('now'));

-- CA DRE — Real Estate Licensing
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_084', 'ETHICARA', 'STATE_STATUTE', 'CA', 'Cal. Bus. & Prof. Code §§ 10130-10261 (Real Estate Law)', 'BPC §§ 10130-10261', 'California Department of Real Estate — Real Estate Licensing', 'Governs licensure and regulation of real estate brokers and salespersons in California. DRE oversees licensing examinations, continuing education, trust fund handling, and disciplinary actions. Brokers supervise salespersons. License required for any activity involving the sale, lease, or exchange of real property for compensation. Trust fund handling governed by strict requirements including separate accounts and monthly reconciliation.', '["License required to perform real estate activities for compensation (§ 10130)","Salesperson license: 3 college-level courses, written exam (§ 10153.2)","Broker license: 8 college-level courses, 2 years experience, written exam (§ 10153.4)","License renewal: every 4 years, 45 CE hours required (§ 10170.5)","First renewal: 45 hours including specific mandatory topics (ethics, fair housing, trust funds)","Trust fund handling: separate client trust account, monthly reconciliation (§ 10145)","Supervision: broker must supervise all salesperson activities (§ 10159.2)","Agency disclosure: required in residential transactions (CC § 2079.16)","Transfer Disclosure Statement: required for 1-4 residential units (CC § 1102)","Grounds for discipline: fraud, misrepresentation, commingling trust funds (§ 10176-10177)","Recovery Account: fund for victims of licensee fraud (§ 10470)"]', '[{"section":"10130-10131","description":"License required — real estate activities defined"},{"section":"10137","description":"Salesperson must be employed by broker"},{"section":"10145","description":"Trust fund handling — separate accounts, reconciliation"},{"section":"10153.2","description":"Salesperson license requirements — education, exam"},{"section":"10153.4","description":"Broker license requirements — education, experience, exam"},{"section":"10159.2","description":"Broker supervision of salespersons"},{"section":"10170.5","description":"Continuing education — 45 hours per renewal"},{"section":"10176-10177","description":"Grounds for discipline — fraud, misrepresentation"},{"section":"10470-10490","description":"Recovery Account for fraud victims"}]', '["real_estate_license","broker_license","trust_fund_records","CE_records","agency_disclosure","TDS","disciplinary_complaint","trust_account_reconciliation","recovery_claim"]', '["professional-ethics-standards-audit"]', 'California Department of Real Estate (DRE)', 0, 1, datetime('now'), datetime('now'));

-- CA Notary Public Duties
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_085', 'ETHICARA', 'STATE_STATUTE', 'CA', 'Cal. Gov''t Code §§ 8200-8230 (Notary Public)', 'GC §§ 8200-8230', 'California Notary Public — Appointment, Duties, and Obligations', 'Governs appointment, duties, and regulation of notary publics in California. Secretary of State appoints notaries for 4-year terms. Notaries perform acknowledgments, jurats, oaths, and certify copies of powers of attorney. Must maintain a sequential journal of all notarial acts. Personal appearance of signer required for all notarizations. Satisfactory evidence of identity required. $15,000 surety bond and oath of office required.', '["Appointment by Secretary of State for 4-year term (§ 8201)","Requirements: California resident, pass written exam, background check (§ 8201.1)","$15,000 surety bond and oath of office required (§ 8212)","Sequential journal of all notarial acts required (§ 8206)","Journal entry must include: date, type of act, document type, signer identity (§ 8206)","Personal appearance of signer required — no remote notarization for paper documents (§ 8206(a)(2))","Satisfactory evidence of identity: government-issued photo ID or credible witness (§ 8206)","Notarial acts: acknowledgments, jurats, oaths, copy certifications of power of attorney (§ 8205)","Thumbprint required in journal for deeds, quitclaim deeds, deeds of trust, powers of attorney (§ 8206)","Fees: $15 per signature per notarial act (§ 8211)","Misconduct: revocation, civil liability, criminal penalties for fraud (§ 8214-8228)"]', '[{"section":"8200","description":"Appointment — Secretary of State authority"},{"section":"8201-8201.1","description":"Qualifications — residency, exam, background check"},{"section":"8205","description":"Powers — authorized notarial acts"},{"section":"8206","description":"Journal — required entries, personal appearance, identity"},{"section":"8207","description":"Official seal — requirements and specifications"},{"section":"8211","description":"Fees — $15 per signature per notarial act"},{"section":"8212","description":"Bond — $15,000 surety bond required"},{"section":"8214","description":"Grounds for revocation or suspension"},{"section":"8214.1","description":"Liability for failure to require personal appearance"},{"section":"8228","description":"Criminal penalties — forgery, fraud"}]', '["notary_commission","notary_journal","surety_bond","oath_of_office","acknowledgment_certificate","jurat_certificate","identity_verification","disciplinary_complaint"]', '["professional-ethics-standards-audit"]', 'California Secretary of State', 0, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- REGULIS — Construction Standards
-- ═══════════════════════════════════════════════════════════════════════════

-- CA Title 24 Building Standards Code
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_163', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Health & Safety Code § 18901 et seq. (California Building Standards Law); CCR Title 24', 'H&S § 18901+ / CCR Title 24', 'California Title 24 Building Standards Code', 'Comprehensive building standards code adopted by the California Building Standards Commission (CBSC). Title 24 of the California Code of Regulations incorporates and amends the International Building Code (IBC) with California-specific amendments. Twelve parts covering building, electrical, mechanical, plumbing, energy, fire, green building, accessibility, and more. Triennial code cycle with mid-cycle supplements. Local jurisdictions may adopt more restrictive amendments.', '["Title 24 is the California Building Standards Code — 12 parts (CCR Title 24)","Adopted by California Building Standards Commission (CBSC) (H&S § 18901)","Triennial code cycle with interim supplements","Part 1: Administrative Code","Part 2: California Building Code (based on IBC with CA amendments)","Part 3: California Electrical Code (based on NEC/NFPA 70)","Part 4: California Mechanical Code (based on UMC)","Part 5: California Plumbing Code (based on UPC)","Part 6: California Energy Code (energy efficiency standards)","Part 8: Historical Building Code","Part 9: California Fire Code (based on IFC)","Part 11: CALGreen — California Green Building Standards Code","Part 12: California Referenced Standards Code","Local jurisdictions enforce through building permits and inspections"]', '[{"section":"H&S § 18901","description":"California Building Standards Law — authority"},{"section":"Part 2","description":"California Building Code — structural, fire-life safety"},{"section":"Part 3","description":"California Electrical Code — NEC with CA amendments"},{"section":"Part 4","description":"California Mechanical Code — HVAC, exhaust"},{"section":"Part 5","description":"California Plumbing Code — water, waste, gas"},{"section":"Part 6","description":"California Energy Code — energy efficiency (Title 24 Part 6)"},{"section":"Part 9","description":"California Fire Code — fire prevention, access"},{"section":"Part 11","description":"CALGreen — mandatory green building standards"},{"section":"CBC Ch. 11A/11B","description":"Accessibility — private (11A) and public (11B) buildings"}]', '["building_permit","plan_check","inspection_report","code_compliance_analysis","energy_compliance_report","accessibility_analysis","fire_safety_report","green_building_checklist"]', '["california-construction-compliance-audit"]', 'Local Building Departments / CBSC / DSA / OSHPD', 0, 1, datetime('now'), datetime('now'));

-- ADA Title III — Public Accommodations Accessibility
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_164', 'REGULIS', 'FEDERAL_STATUTE', 'US', '42 USC §§ 12181-12189 (Americans with Disabilities Act, Title III — Public Accommodations)', 'ADA Title III / 42 USC §§ 12181-12189', 'ADA Title III — Public Accommodations and Commercial Facilities Accessibility', 'Prohibits discrimination on the basis of disability in places of public accommodation and commercial facilities. Covers 12 categories of public accommodations including restaurants, hotels, theaters, retail stores, healthcare offices, and educational institutions. Requires removal of architectural barriers where readily achievable. New construction and alterations must comply with ADA Standards for Accessible Design. Auxiliary aids and services required for effective communication.', '["Prohibition on disability discrimination by places of public accommodation (§ 12182)","12 categories of public accommodations defined (§ 12181(7))","Full and equal enjoyment of goods, services, facilities (§ 12182(a))","Reasonable modifications to policies, practices, procedures (§ 12182(b)(2)(A)(ii))","Auxiliary aids and services for effective communication (§ 12182(b)(2)(A)(iii))","Barrier removal: readily achievable removal of architectural barriers (§ 12182(b)(2)(A)(iv))","New construction: must comply with ADA Standards for Accessible Design (§ 12183(a))","Alterations: altered portions must be accessible; path of travel (§ 12183(a)(2))","No surcharge for accommodations provided to persons with disabilities","Private right of action for injunctive relief (§ 12188(a))","DOJ enforcement: pattern or practice, civil penalties up to $75,000/$150,000 (§ 12188(b))"]', '[{"section":"12181(7)","description":"12 categories of public accommodations defined"},{"section":"12182(a)","description":"General prohibition on disability discrimination"},{"section":"12182(b)(2)(A)(ii)","description":"Reasonable modifications requirement"},{"section":"12182(b)(2)(A)(iii)","description":"Auxiliary aids and services"},{"section":"12182(b)(2)(A)(iv)","description":"Barrier removal — readily achievable standard"},{"section":"12183(a)(1)","description":"New construction — accessible design required"},{"section":"12183(a)(2)","description":"Alterations — path of travel requirements"},{"section":"12188(a)","description":"Private right of action — injunctive relief"},{"section":"12188(b)","description":"DOJ enforcement — civil penalties"},{"section":"28 CFR Part 36","description":"DOJ implementing regulations — ADA Standards"}]', '["ADA_compliance_survey","barrier_removal_plan","accessibility_audit","architectural_analysis","auxiliary_aids_policy","reasonable_modification_request","DOJ_complaint","private_action_complaint"]', '["california-construction-compliance-audit"]', 'U.S. Department of Justice / Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- Rehabilitation Act Section 504
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_165', 'REGULIS', 'FEDERAL_STATUTE', 'US', '29 USC § 794 (Rehabilitation Act of 1973, Section 504)', 'Section 504 / 29 USC § 794', 'Rehabilitation Act Section 504 — Nondiscrimination by Federal Fund Recipients', 'Prohibits discrimination on the basis of disability in programs and activities receiving federal financial assistance. Broader reach than ADA in some contexts because it covers any entity receiving federal funds, including schools, hospitals, housing authorities, and state/local agencies. Requires reasonable accommodations, program accessibility, and effective communication. Private right of action for damages (not just injunctive relief). Predates and serves as model for ADA.', '["No exclusion from participation solely by reason of disability (§ 794(a))","Applies to any program or activity receiving federal financial assistance","Federal financial assistance includes grants, loans, contracts, subsidies","Reasonable accommodations required for qualified individuals with disabilities","Program accessibility: existing programs must be accessible as a whole","New construction by recipients must be fully accessible","Effective communication: auxiliary aids required","Individual with a disability: physical or mental impairment substantially limiting major life activity","Private right of action: compensatory damages available (Barnes v. Gorman qualified)","Exhaustion of administrative remedies not always required","Applies to public schools, universities, hospitals, housing authorities, transit"]', '[{"section":"794(a)","description":"Nondiscrimination requirement — federal fund recipients"},{"section":"794(b)","description":"Program or activity defined — broad institutional coverage"},{"section":"794(d)","description":"Standards — consistent with ADA Title II regulations"},{"section":"34 CFR Part 104","description":"HHS/ED implementing regulations — education context"},{"section":"45 CFR Part 84","description":"HHS implementing regulations — healthcare context"},{"section":"28 CFR § 42.501","description":"DOJ coordination regulations"}]', '["Section_504_complaint","accommodation_request","program_accessibility_plan","self_evaluation","transition_plan","compliance_review","OCR_complaint","funding_agency_complaint"]', '["california-construction-compliance-audit"]', 'Federal funding agency (OCR, HHS, etc.) / Federal Courts', 1, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- FORGE-0 — Digital Accessibility Standards
-- ═══════════════════════════════════════════════════════════════════════════

-- WCAG 2.1
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_for_004', 'FORGE-0', 'PROFESSIONAL_STANDARD', 'INTERNATIONAL', 'W3C Web Content Accessibility Guidelines (WCAG) 2.1 (June 2018)', 'WCAG 2.1', 'WCAG 2.1 — Web Content Accessibility Guidelines', 'International standard developed by W3C Web Accessibility Initiative (WAI) for making web content accessible to people with disabilities. Organized around four principles: Perceivable, Operable, Understandable, and Robust (POUR). Three conformance levels: A (minimum), AA (target for most legal requirements), AAA (highest). WCAG 2.1 adds 17 new success criteria to WCAG 2.0, addressing mobile accessibility, low vision, and cognitive disabilities. Referenced by Section 508, ADA case law, EN 301 549, and many state laws.', '["Four principles: Perceivable, Operable, Understandable, Robust (POUR)","Conformance Level A: 30 success criteria (minimum baseline)","Conformance Level AA: 20 additional success criteria (standard legal target)","Conformance Level AAA: 28 additional success criteria (enhanced)","Perceivable: text alternatives, captions, adaptable content, distinguishable","Operable: keyboard accessible, enough time, no seizures, navigable, input modalities","Understandable: readable, predictable, input assistance","Robust: compatible with assistive technologies","WCAG 2.1 new: orientation, identify input purpose, reflow, text spacing, content on hover/focus","WCAG 2.1 new: pointer gestures, pointer cancellation, label in name, motion actuation, status messages","Level AA is the standard referenced by most legal frameworks","Backward compatible: conforming to 2.1 also conforms to 2.0"]', '[{"section":"1.1","description":"Perceivable — text alternatives for non-text content"},{"section":"1.2","description":"Perceivable — time-based media alternatives"},{"section":"1.3","description":"Perceivable — adaptable — content structure"},{"section":"1.4","description":"Perceivable — distinguishable — color, contrast, resize"},{"section":"2.1","description":"Operable — keyboard accessible"},{"section":"2.4","description":"Operable — navigable — focus, headings, labels"},{"section":"2.5","description":"Operable — input modalities (new in 2.1)"},{"section":"3.1","description":"Understandable — readable"},{"section":"3.3","description":"Understandable — input assistance — error identification"},{"section":"4.1","description":"Robust — compatible with assistive technologies"}]', '["WCAG_audit_report","VPAT","accessibility_conformance_report","remediation_plan","accessibility_statement","automated_scan_results","manual_testing_results","assistive_technology_test_results"]', '["autonomous-build-compliance-audit"]', 'W3C (voluntary) / Referenced by federal and state law', 0, 1, datetime('now'), datetime('now'));

-- Section 508
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_for_005', 'FORGE-0', 'FEDERAL_STATUTE', 'US', '29 USC § 794d (Rehabilitation Act, Section 508 — Electronic and Information Technology)', 'Section 508 / 29 USC § 794d', 'Section 508 — Federal Electronic and Information Technology Accessibility', 'Requires federal agencies to make their electronic and information technology (EIT) accessible to people with disabilities. Refreshed standards (2017) incorporate WCAG 2.0 Level AA as the baseline for web content and non-web electronic documents. Applies to federal agencies and contractors providing EIT to the federal government. Covers websites, software, hardware, multimedia, and electronic documents. Enforced through administrative complaints and procurement requirements.', '["Federal agencies must ensure EIT is accessible to people with disabilities (§ 794d(a))","Refreshed standards (January 2017): incorporate WCAG 2.0 Level AA","Applies to: websites, software applications, electronic documents, multimedia","Applies to: hardware, telecommunications products, self-service machines","Procurement: federal contracts must specify Section 508 compliance","VPAT (Voluntary Product Accessibility Template) used by vendors to document conformance","Exceptions: national security, incidental use, fundamental alteration, undue burden","Undue burden: alternative means of access must be provided","Administrative complaint process through the agency","Private right of action available against federal agencies","Applies to contractors providing EIT to federal government","EN 301 549 (European) harmonized with Section 508 refreshed standards"]', '[{"section":"794d(a)(1)(A)","description":"Development and procurement — accessible EIT required"},{"section":"794d(a)(1)(B)","description":"Alternative means when exceptions apply"},{"section":"794d(b)","description":"Technical standards — Access Board authority"},{"section":"794d(f)","description":"Enforcement — administrative complaints"},{"section":"36 CFR Part 1194","description":"Access Board technical standards (refreshed 2017)"},{"section":"E205","description":"Electronic content — WCAG 2.0 AA incorporated"},{"section":"E207","description":"Software — WCAG 2.0 AA + additional criteria"},{"section":"E208","description":"Support documentation and services"}]', '["VPAT","Section_508_audit","accessibility_conformance_report","procurement_requirement","administrative_complaint","remediation_plan","alternative_access_plan","conformance_testing_report"]', '["autonomous-build-compliance-audit"]', 'U.S. Access Board / Federal Agencies / Federal Courts', 1, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- SYNTARA — Additional Technology Standards
-- ═══════════════════════════════════════════════════════════════════════════

-- PCI DSS v4.0
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_syn_007', 'SYNTARA', 'PROFESSIONAL_STANDARD', 'INTERNATIONAL', 'PCI DSS v4.0 (March 2022; mandatory March 31, 2025)', 'PCI DSS v4.0', 'PCI DSS v4.0 — Payment Card Industry Data Security Standard', 'Industry security standard developed by PCI Security Standards Council (PCI SSC) for protecting payment card data. Applies to all entities that store, process, or transmit cardholder data. Twelve principal requirements organized into six goals. Version 4.0 introduces customized approach as alternative to defined approach, expanded multi-factor authentication, and targeted risk analysis. Non-compliance may result in fines from card brands ($5,000-$100,000/month), increased transaction fees, or loss of card processing privileges.', '["Applies to all entities storing, processing, or transmitting cardholder data","12 principal requirements organized into 6 goals","Goal 1: Build and maintain a secure network (Requirements 1-2)","Goal 2: Protect account data (Requirements 3-4)","Goal 3: Maintain a vulnerability management program (Requirements 5-6)","Goal 4: Implement strong access control measures (Requirements 7-9)","Goal 5: Regularly monitor and test networks (Requirements 10-11)","Goal 6: Maintain an information security policy (Requirement 12)","v4.0: Customized approach — alternative to defined approach with TPR","v4.0: Expanded MFA — required for all access to cardholder data environment","v4.0: Targeted risk analysis replaces broad risk assessment","Validation: SAQ (self-assessment) or QSA (qualified security assessor) audit","Compliance levels based on transaction volume (Level 1: 6M+, Level 4: <20K)"]', '[{"section":"Requirement 1","description":"Install and maintain network security controls"},{"section":"Requirement 2","description":"Apply secure configurations to all system components"},{"section":"Requirement 3","description":"Protect stored account data — encryption, masking, retention"},{"section":"Requirement 4","description":"Protect cardholder data with strong cryptography during transmission"},{"section":"Requirement 5","description":"Protect all systems against malware"},{"section":"Requirement 6","description":"Develop and maintain secure systems and software"},{"section":"Requirement 7","description":"Restrict access by business need to know"},{"section":"Requirement 8","description":"Identify users and authenticate access — MFA expanded"},{"section":"Requirement 9","description":"Restrict physical access to cardholder data"},{"section":"Requirement 10","description":"Log and monitor all access to system components and cardholder data"},{"section":"Requirement 11","description":"Test security of systems and networks regularly"},{"section":"Requirement 12","description":"Support information security with organizational policies and programs"}]', '["SAQ","ROC","AOC","QSA_report","ASV_scan","penetration_test","network_diagram","data_flow_diagram","risk_assessment","incident_response_plan","encryption_inventory"]', '["technology-compliance-audit"]', 'PCI SSC / Card Brands (Visa, Mastercard, Amex, Discover)', 0, 1, datetime('now'), datetime('now'));

-- HITRUST CSF
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_syn_008', 'SYNTARA', 'PROFESSIONAL_STANDARD', 'US', 'HITRUST CSF v11 (Health Information Trust Alliance Common Security Framework)', 'HITRUST CSF v11', 'HITRUST CSF — Health Information Trust Alliance Common Security Framework', 'Certifiable framework that provides organizations with a comprehensive, flexible, and efficient approach to regulatory compliance and risk management. Harmonizes requirements from HIPAA, ISO 27001, NIST CSF, PCI DSS, SOC 2, GDPR, and other frameworks into a single assessment. Three assessment types: e1 (essentials, 44 controls), i1 (implemented, 182 controls), r2 (risk-based, comprehensive). HITRUST certification widely recognized in healthcare, insurance, and financial services as demonstrating due diligence for information protection.', '["Harmonized framework incorporating 40+ authoritative sources","Maps to HIPAA, ISO 27001/27002, NIST CSF/800-53, PCI DSS, SOC 2, GDPR","Three assessment levels: e1 (essentials), i1 (implemented), r2 (risk-based)","e1 assessment: 44 requirement statements — foundational cybersecurity practices","i1 assessment: 182 requirement statements — leading security practices","r2 assessment: comprehensive — tailored to organizational risk factors","19 control domains covering security, privacy, and compliance","Certification valid for 2 years (r2) or 1 year (e1/i1)","Assessed by HITRUST-authorized external assessor organizations","Inheritance program: cloud providers can share certifications with customers","CSF Assurance Program: standardized methodology for assessment","Widely accepted as evidence of HIPAA compliance due diligence"]', '[{"section":"Domain 0","description":"Information Security Management Program"},{"section":"Domain 1","description":"Access Control"},{"section":"Domain 2","description":"Human Resources Security"},{"section":"Domain 3","description":"Risk Management"},{"section":"Domain 5","description":"Information Protection Program"},{"section":"Domain 6","description":"Endpoint Protection"},{"section":"Domain 8","description":"Network Protection"},{"section":"Domain 9","description":"Transmission Protection"},{"section":"Domain 10","description":"Vulnerability Management"},{"section":"Domain 11","description":"Configuration Management"},{"section":"Domain 14","description":"Third Party Assurance"},{"section":"Domain 19","description":"Data Protection and Privacy"}]', '["HITRUST_certification","e1_assessment","i1_assessment","r2_assessment","corrective_action_plan","inheritance_documentation","risk_analysis","control_maturity_assessment","external_assessor_report","gap_analysis"]', '["technology-compliance-audit"]', 'HITRUST Alliance', 0, 1, datetime('now'), datetime('now'));

-- StateRAMP
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_syn_009', 'SYNTARA', 'PROFESSIONAL_STANDARD', 'US', 'StateRAMP (State Risk and Authorization Management Program)', 'StateRAMP', 'StateRAMP — State Risk and Authorization Management Program', 'Nonprofit organization providing a standardized approach for state and local governments to verify cloud service provider (CSP) security. Modeled on FedRAMP but tailored for state/local government procurement. Uses NIST 800-53 controls at three impact levels (Low, Moderate, High). StateRAMP Authorized Product List provides verified CSPs for government procurement. Continuous monitoring required after authorization. Growing adoption across states as standard for cloud procurement security verification.', '["Standardized security verification for cloud service providers serving state/local government","Based on NIST SP 800-53 security controls","Three impact levels: Low, Moderate, High (mirroring FedRAMP)","Low impact: ~125 controls — non-sensitive data","Moderate impact: ~325 controls — controlled unclassified information","High impact: ~421 controls — critical systems and sensitive data","Authorization process: readiness assessment, security assessment, authorization decision","StateRAMP Authorized Product List: verified CSPs for government use","Third-party assessment organization (3PAO) conducts security assessment","Continuous monitoring: monthly vulnerability scans, annual assessments","Reciprocity with FedRAMP: FedRAMP authorized CSPs have streamlined path","Snapshots: interim status for CSPs working toward full authorization","Growing adoption: 20+ states recognize or require StateRAMP"]', '[{"section":"Security Category: Low","description":"~125 NIST controls — basic security posture"},{"section":"Security Category: Moderate","description":"~325 NIST controls — standard government data"},{"section":"Security Category: High","description":"~421 NIST controls — sensitive/critical systems"},{"section":"Readiness Assessment","description":"Initial gap analysis and readiness determination"},{"section":"Security Assessment","description":"3PAO assessment of control implementation"},{"section":"Authorization Decision","description":"StateRAMP PMO review and authorization"},{"section":"Continuous Monitoring","description":"Ongoing compliance — scans, POA&Ms, annual assessments"},{"section":"Snapshots","description":"Interim status categories for in-progress CSPs"}]', '["StateRAMP_authorization","SSP","SAR","POA_M","3PAO_assessment","continuous_monitoring_report","vulnerability_scan","readiness_assessment","authorized_product_listing","annual_assessment"]', '["technology-compliance-audit"]', 'StateRAMP (nonprofit)', 0, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- REGULIS — Anti-Discrimination Standards
-- ═══════════════════════════════════════════════════════════════════════════

-- ADA Title I — Employment Disability Discrimination
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_166', 'REGULIS', 'FEDERAL_STATUTE', 'US', '42 USC §§ 12111-12117 (Americans with Disabilities Act, Title I — Employment)', 'ADA Title I / 42 USC §§ 12111-12117', 'ADA Title I — Employment Discrimination Based on Disability', 'Prohibits covered employers (15+ employees) from discriminating against qualified individuals with disabilities in all aspects of employment: hiring, promotion, discharge, compensation, training, and terms/conditions. Requires reasonable accommodation unless undue hardship. Interactive process required to identify effective accommodations. Prohibits medical examinations and disability-related inquiries pre-offer. EEOC enforces; private right of action after exhausting administrative remedies.', '["Applies to employers with 15+ employees (§ 12111(5))","Prohibits discrimination against qualified individuals with disabilities (§ 12112(a))","Qualified individual: can perform essential functions with or without accommodation","Reasonable accommodation required unless undue hardship (§ 12112(b)(5)(A))","Interactive process: employer and employee must engage in good faith dialogue","Examples of accommodation: modified schedule, reassignment, equipment, job restructuring","Undue hardship: significant difficulty or expense considering employer resources (§ 12111(10))","Pre-offer: no medical exams or disability-related inquiries (§ 12112(d)(2))","Post-offer: medical exam permitted if required of all entering employees (§ 12112(d)(3))","Medical records: must be maintained separately and kept confidential (§ 12112(d)(3)(B))","EEOC charge required before filing suit — 180/300 day deadline","Remedies: back pay, front pay, reinstatement, compensatory/punitive damages (capped)"]', '[{"section":"12111(5)","description":"Covered entity — employer with 15+ employees"},{"section":"12111(8)","description":"Qualified individual — essential functions"},{"section":"12111(9)","description":"Reasonable accommodation defined"},{"section":"12111(10)","description":"Undue hardship factors"},{"section":"12112(a)","description":"General prohibition on discrimination"},{"section":"12112(b)(5)(A)","description":"Failure to accommodate as discrimination"},{"section":"12112(d)","description":"Medical examinations and inquiries — pre/post offer"},{"section":"12116","description":"EEOC enforcement authority"},{"section":"12117","description":"Remedies — incorporated from Title VII"},{"section":"29 CFR Part 1630","description":"EEOC implementing regulations"}]', '["EEOC_charge","accommodation_request","interactive_process_documentation","essential_functions_analysis","undue_hardship_analysis","medical_records","right_to_sue_notice","employment_discrimination_complaint","job_description"]', '["california-labor-employment-audit"]', 'EEOC / Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- ADA Title II — State/Local Government Accessibility
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_167', 'REGULIS', 'FEDERAL_STATUTE', 'US', '42 USC §§ 12131-12165 (Americans with Disabilities Act, Title II — Public Services)', 'ADA Title II / 42 USC §§ 12131-12165', 'ADA Title II — State and Local Government Services Accessibility', 'Prohibits state and local governments from discriminating against qualified individuals with disabilities in services, programs, and activities. No minimum employee threshold — applies to all public entities regardless of size. Requires program accessibility for existing facilities and full accessibility for new construction and alterations. Covers public transportation (Subtitle B). Self-evaluation and transition plan required. Private right of action for injunctive relief and damages. DOJ and federal funding agencies enforce.', '["No qualified individual with a disability shall be excluded from participation (§ 12132)","Public entity: any state or local government, department, agency, instrumentality (§ 12131(1))","No minimum size — applies to all public entities regardless of employees or budget","Program accessibility: existing programs must be accessible as a whole","New construction and alterations: must comply with ADA Standards for Accessible Design","Self-evaluation required: review policies and practices for discrimination (28 CFR § 35.105)","Transition plan required for structural changes needed for program accessibility (28 CFR § 35.150)","Reasonable modifications to policies, practices, and procedures (28 CFR § 35.130(b)(7))","Effective communication: auxiliary aids and services required (28 CFR § 35.160)","Subtitle B: public transportation — paratransit, fixed route, rail (§§ 12141-12165)","Private right of action: injunctive relief and compensatory damages available","No exhaustion of administrative remedies required before suit"]', '[{"section":"12131(1)","description":"Public entity defined — all state and local government entities"},{"section":"12132","description":"Prohibition on discrimination by public entities"},{"section":"12133","description":"Enforcement — remedies of Section 504 incorporated"},{"section":"12134","description":"DOJ regulations — authority to issue"},{"section":"12141-12165","description":"Public transportation — paratransit, fixed route, intercity rail"},{"section":"28 CFR Part 35","description":"DOJ implementing regulations"},{"section":"28 CFR § 35.105","description":"Self-evaluation requirement"},{"section":"28 CFR § 35.150","description":"Transition plan for existing facilities"},{"section":"28 CFR § 35.160","description":"Effective communication — auxiliary aids"}]', '["ADA_Title_II_complaint","self_evaluation","transition_plan","program_accessibility_analysis","reasonable_modification_request","effective_communication_plan","DOJ_complaint","architectural_survey","grievance_procedure","ADA_coordinator_designation"]', '["california-labor-employment-audit"]', 'U.S. Department of Justice / Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- Unruh Civil Rights Act
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_168', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code § 51 (Unruh Civil Rights Act)', 'CC § 51 / Unruh Act', 'Unruh Civil Rights Act — California Broadest Anti-Discrimination Statute', 'Guarantees full and equal accommodations, advantages, facilities, privileges, or services in all business establishments in California regardless of sex, race, color, religion, ancestry, national origin, disability, medical condition, genetic information, marital status, sexual orientation, citizenship, primary language, or immigration status. Broader than federal civil rights laws: California courts have held the enumerated categories are illustrative, not exhaustive (Marina Point v. Wolfson). ADA violations constitute Unruh violations per CC § 51(f). Statutory damages of $4,000 minimum per violation plus actual damages and attorney fees.', '["Full and equal accommodations in all business establishments (§ 51(b))","Protected categories: sex, race, color, religion, ancestry, national origin, disability, medical condition, genetic information, marital status, sexual orientation, citizenship, primary language, immigration status","Categories are illustrative, not exhaustive (Marina Point v. Wolfson, 1982)","Business establishment: broadly interpreted — any business operation","ADA violation = Unruh violation (§ 51(f)) — no independent intent required","Statutory minimum damages: $4,000 per violation (§ 52(a))","Actual damages available in addition to statutory damages","Attorney fees and costs to prevailing plaintiff (§ 52(a))","Treble damages available for certain violations (§ 52(b))","No government entity defendant — applies to private business establishments","Intersectionality recognized — compound discrimination actionable","Age discrimination covered: arbitrary age-based exclusions prohibited"]', '[{"section":"51(a)","description":"Legislative declaration — equal rights regardless of listed characteristics"},{"section":"51(b)","description":"Full and equal accommodations in all business establishments"},{"section":"51(e)","description":"Disability defined — consistent with ADA"},{"section":"51(f)","description":"ADA violation constitutes Unruh violation"},{"section":"52(a)","description":"Remedies — $4,000 statutory minimum, actual damages, attorney fees"},{"section":"52(b)","description":"Treble damages for specified violations"},{"section":"52(c)","description":"Denial of civil rights — independent cause of action"},{"section":"Marina Point v. Wolfson","description":"Categories illustrative, not exhaustive (1982)"},{"section":"Munson v. Del Taco","description":"ADA violation is per se Unruh violation"}]', '["Unruh_complaint","DFEH_complaint","discrimination_claim","statutory_damages_calculation","accommodation_request","business_policy_review","accessibility_audit","actual_damages_documentation","attorney_fee_petition"]', '["california-labor-employment-audit"]', 'California Civil Rights Department (CRD) / Superior Court', 1, 1, datetime('now'), datetime('now'));
